class SpamDetector:
    def __init__(self):
        self.model = None
        self.vectorizer = None
        self.train_model()
        
    def preprocess_text(self, text):
        text = text.lower()
        text = re.sub(r'http\S+|www\S+', 'URL', text)
        text = re.sub(r'\S+@\S+', 'EMAIL', text)
        text = re.sub(r'\d+', 'NUM', text)
        text = re.sub(f'[{re.escape(string.punctuation)}]', ' ', text)
        text = re.sub(r'\s+', ' ', text).strip()
        return text
    
    def extract_features(self, text):
        features = {}
        features['length'] = len(text)
        features['uppercase_ratio'] = sum(1 for c in text if c.isupper()) / max(len(text), 1)
        features['exclamation_count'] = text.count('!')
        features['question_count'] = text.count('?')
        features['dollar_count'] = text.count('$')
        features['url_count'] = len(re.findall(r'http\S+|www\S+', text))
        
        spam_keywords = ['free', 'win', 'winner', 'cash', 'prize', 'urgent', 'act now', 
                        'limited time', 'click here', 'buy now', 'guarantee', 'offer']
        features['spam_keyword_count'] = sum(keyword in text.lower() for keyword in spam_keywords)
        
        return features
    
    def train_model(self):
        texts = [email[0] for email in training_emails]
        labels = [email[1] for email in training_emails]
        
        processed_texts = [self.preprocess_text(text) for text in texts]
        
        self.vectorizer = TfidfVectorizer(
            max_features=100,
            ngram_range=(1, 2),
            min_df=1,
            max_df=0.8,
            sublinear_tf=True
        )
        
        X_text = self.vectorizer.fit_transform(processed_texts)
        
        additional_features = np.array([list(self.extract_features(text).values()) for text in texts])
        X_combined = np.hstack([X_text.toarray(), additional_features])
        
        self.model = LogisticRegression(
            C=1.0,
            class_weight='balanced',
            max_iter=1000,
            random_state=42
        )
        self.model.fit(X_combined, labels)
    
    def predict(self, text):
        processed_text = self.preprocess_text(text)
        X_text = self.vectorizer.transform([processed_text])
        additional_features = np.array([list(self.extract_features(text).values())])
        X_combined = np.hstack([X_text.toarray(), additional_features])
        
        probability = self.model.predict_proba(X_combined)[0][1]
        return float(probability)

detector = SpamDetector()

def get_client_id(request):
    forwarded_for = request.headers.get('X-Forwarded-For')
    if forwarded_for:
        ip = forwarded_for.split(',')[0].strip()
    else:
        ip = request.remote_addr
    
    user_agent = request.headers.get('User-Agent', '')
    client_string = f"{ip}:{user_agent}"
    return hashlib.sha256(client_string.encode()).hexdigest()

def check_rate_limit(client_id):
    with rate_limit_lock:
        now = datetime.now()
        client_data = request_counts[client_id]
        
        if now > client_data['reset_time']:
            client_data['count'] = 0
            client_data['reset_time'] = now + timedelta(minutes=1)
        
        if client_data['count'] >= MAX_REQUESTS_PER_MINUTE:
            return False
        
        client_data['count'] += 1
        return True

def validate_email_text(text):
    if not isinstance(text, str):
        return False, "Email text must be a string"
    
    if len(text) < MIN_EMAIL_LENGTH:
        return False, f"Email text too short (minimum {MIN_EMAIL_LENGTH} characters)"
    
    if len(text) > MAX_EMAIL_LENGTH:
        return False, f"Email text too long (maximum {MAX_EMAIL_LENGTH} characters)"
    
    non_printable = sum(1 for c in text if c not in string.printable)
    if non_printable > len(text) * 0.1:
        return False, "Email contains too many non-printable characters"
    
    return True, None

def detect_evasion_attempt(text):
    suspicious_patterns = 0
    
    if re.search(r'(.)\1{10,}', text):
        suspicious_patterns += 1
    
    whitespace_ratio = sum(1 for c in text if c.isspace()) / len(text)
    if whitespace_ratio > 0.5:
        suspicious_patterns += 1
    
    if len(re.findall(r'[^\w\s]', text)) > len(text) * 0.3:
        suspicious_patterns += 1
    
    zero_width_chars = ['\u200b', '\u200c', '\u200d', '\ufeff']
    if any(char in text for char in zero_width_chars):
        suspicious_patterns += 1
    
    if re.search(r'[a-z][A-Z][a-z][A-Z]', text):
        suspicious_patterns += 1
    
    return suspicious_patterns >= SUSPICIOUS_PATTERN_THRESHOLD

