@app.route('/batch_predict', methods=['POST'])
def batch_predict():
    client_id = get_client_id(request)
    
    if not check_rate_limit(client_id):
        return jsonify({
            'error': 'Rate limit exceeded',
            'message': f'Maximum {MAX_REQUESTS_PER_MINUTE} requests per minute allowed'
        }), 429
    
    try:
        data = request.get_json()
        
        if not data or 'emails' not in data:
            return jsonify({'error': 'Missing emails field'}), 400
        
        emails = data['emails']
        
        if not isinstance(emails, list):
            return jsonify({'error': 'emails must be a list'}), 400
        
        if len(emails) > 100:
            return jsonify({'error': 'Maximum 100 emails per batch'}), 400
        
        results = []
        for idx, email_text in enumerate(emails):
            is_valid, error_message = validate_email_text(email_text)
            if not is_valid:
                results.append({
                    'index': idx,
                    'error': error_message
                })
                continue
            
            if detect_evasion_attempt(email_text):
                results.append({
                    'index': idx,
                    'spam_probability': 0.95,
                    'is_spam': True,
                    'warning': 'Potential evasion attempt detected'
                })
                continue
            
            spam_probability = detector.predict(email_text)
            results.append({
                'index': idx,
                'spam_probability': round(spam_probability, 4),
                'is_spam': spam_probability > 0.5
            })
        
        return jsonify({
            'results': results,
            'timestamp': datetime.now().isoformat()
        })
    
    except Exception as e:
        return jsonify({'error': 'Internal server error', 'message': str(e)}), 500

